}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	var summaries []UserActivitySummary

	// Handle empty usernames
	if len(usernames) == 0 {
		return nil, fmt.Errorf("not enough args to execute query: want at least 1 username, got 0")
	}

	// Build placeholders for IN clause
	placeholders := ""
	for i, _ := range usernames {
		if i > 0 {
			placeholders += ", "
		}
		placeholders += "?"
	}

	// Build SQL query
	sql := fmt.Sprintf(`
		SELECT u.display_name, a.action_type, COUNT(*) as total, 
			SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
			AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (%s) AND a.created_at BETWEEN ? AND ?
	`, placeholders)

	// Build params
	params := make([]interface{}, 0, len(usernames)+2)
	for _, username := range usernames {
		params = append(params, username)
	}
	params = append(params, startDate, endDate)

	if actionTypeFilter != "" {
		sql += " AND a.action_type = ?"
		params = append(params, actionTypeFilter)
	}

	sql += " GROUP BY u.display_name, a.action_type"

	// Execute query
	_, err := o.Raw(sql, params...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}

	return summaries, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate groupByField
	if groupByField != "department" && groupByField != "role" && groupByField != "display_name" {
		return nil, fmt.Errorf("invalid groupByField: %s. Must be one of: department, role, display_name", groupByField)
	}

	// Handle empty departments
	if len(departments) == 0 {
		return nil, fmt.Errorf("not enough args to execute query: want at least 1 department, got 0")
	}

	// Build placeholders for IN clause
	placeholders := ""
	for i, _ := range departments {
		if i > 0 {
			placeholders += ", "
		}
		placeholders += "?"
	}

	// Build SQL query
	sql := fmt.Sprintf(`
		SELECT u.%s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY u.%s
	`, groupByField, placeholders, groupByField)

	// Build params
	params := make([]interface{}, 0, len(departments))
	for _, dept := range departments {
		params = append(params, dept)
	}

	// Execute query and scan into structs
	type ReportRow struct {
		GroupValue      string `orm:"column(group_value)"`
		UserCount       int    `orm:"column(user_count)"`
		TotalActivities int    `orm:"column(total_activities)"`
	}
	var reportRows []ReportRow
	_, err := o.Raw(sql, params...).QueryRows(&reportRows)
	if err != nil {
		return nil, err
	}

	// Convert to []map[string]interface{}
	var reports []map[string]interface{}
	for _, row := range reportRows {
		reports = append(reports, map[string]interface{}{
			"group_value":      row.GroupValue,
			"user_count":       row.UserCount,
			"total_activities": row.TotalActivities,
		})
	}

	return reports, nil
}

