type UserProfile struct {
	Id          int64     `orm:"column(id);pk;auto"`
	Username    string    `orm:"column(username);unique"`
	DisplayName string    `orm:"column(display_name)"`
	Email       string    `orm:"column(email)"`
	Department  string    `orm:"column(department)"`
	Role        string    `orm:"column(role)"`
	CreatedAt   time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivity struct {
	Id         int64     `orm:"column(id);pk;auto"`
	UserId     int64     `orm:"column(user_id)"`
	ActionType string    `orm:"column(action_type)"`
	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id
	return user, nil
}

func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build SQL query
	sql := `SELECT u.display_name, a.action_type, COUNT(*) as total, SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, AVG(a.duration_ms) as avg_duration
            FROM user_activity a JOIN user_profile u ON a.user_id = u.id
            WHERE u.username IN (`

	// Create placeholders for usernames
	params := []interface{}{}
	for i, username := range usernames {
		if i > 0 {
			sql += ", "
		}
		sql += "?"
		params = append(params, username)
	}
	sql += ") AND a.created_at BETWEEN ? AND ?"
	params = append(params, startDate, endDate)

	// Add action type filter if provided
	if actionTypeFilter != "" {
		sql += " AND a.action_type = ?"
		params = append(params, actionTypeFilter)
	}

	sql += " GROUP BY u.display_name, a.action_type"

	// Execute query
	var summary []UserActivitySummary
	_, err := o.Raw(sql, params...).QueryRows(&summary)
	if err != nil {
		return nil, err
	}

	return summary, nil
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid group by field: %s", groupByField)
	}

	// Build SQL query
	sql := `SELECT u.` + groupByField + ` as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
            FROM user_profile u LEFT JOIN user_activity a ON u.id = a.user_id
            WHERE u.department IN (`

	// Create placeholders for departments
	params := []interface{}{}
	for i, dept := range departments {
		if i > 0 {
			sql += ", "
		}
		sql += "?"
		params = append(params, dept)
	}
	sql += ") GROUP BY u." + groupByField

	// Execute query
	var results []struct {
		GroupValue     string `orm:"column(group_value)"`
		UserCount      int64  `orm:"column(user_count)"`
		TotalActivities int64 `orm:"column(total_activities)"`
	}
	_, err := o.Raw(sql, params...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	// Convert to map format
	var reports []map[string]interface{}
	for _, r := range results {
		reports = append(reports, map[string]interface{}{
			"group_value":     r.GroupValue,
			"user_count":      r.UserCount,
			"total_activities": r.TotalActivities,
		})
	}

	return reports, nil
}

