package main

import (
	"fmt"
	"time"

	"github.com/beego/beego/v2/client/orm"
)

type UserProfile struct {
	Id          int64     `orm:"column(id);pk;auto"`
	Username    string    `orm:"column(username);unique"`
	DisplayName string    `orm:"column(display_name)"`
	Email       string    `orm:"column(email)"`
	Department  string    `orm:"column(department)"`
	Role        string    `orm:"column(role)"`
	CreatedAt   time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivity struct {
	Id         int64     `orm:"column(id);pk;auto"`
	UserId     int64     `orm:"column(user_id)"`
	ActionType string    `orm:"column(action_type)"`
	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string  `orm:"column(display_name)"`
	ActionType   string  `orm:"column(action_type)"`
	TotalActions int64   `orm:"column(total)"`
	SuccessCount int64   `orm:"column(success_count)"`
	AvgDuration  float64 `orm:"column(avg_duration)"`
}

func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	_, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	return user, nil
}

func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build IN clause for usernames
	inClause := "("
	params := make([]interface{}, 0, len(usernames)+3) // 3 extra for dates and optional filter
	for _, username := range usernames {
		if len(inClause) > 1 {
			inClause += ", "
		}
		inClause += "?"
		params = append(params, username)
	}
	inClause += ")"

	query := fmt.Sprintf(`SELECT u.display_name, a.action_type, COUNT(*) as total, SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, AVG(a.duration_ms) as avg_duration
	FROM user_activity a JOIN user_profile u ON a.user_id = u.id
	WHERE u.username IN %s AND a.created_at BETWEEN ? AND ?`, inClause)

	params = append(params, startDate, endDate)

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		params = append(params, actionTypeFilter)
	}

	query += " GROUP BY u.display_name, a.action_type"

	var summaries []UserActivitySummary
	_, err := o.Raw(query, params...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}

	return summaries, nil
}

type DepartmentReportRow struct {
	GroupValue     string `orm:"column(group_value)"`
	UserCount      int64  `orm:"column(user_count)"`
	TotalActivities int64 `orm:"column(total_activities)"`
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	validGroupFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}

	if len(departments) == 0 || !validGroupFields[groupByField] {
		return nil, fmt.Errorf("invalid departments or groupByField")
	}

	// Build IN clause for departments
	inClause := "("
	params := make([]interface{}, 0, len(departments))
	for _, dept := range departments {
		if len(inClause) > 1 {
			inClause += ", "
		}
		inClause += "?"
		params = append(params, dept)
	}
	inClause += ")"

	query := fmt.Sprintf(`SELECT u.%s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
	FROM user_profile u LEFT JOIN user_activity a ON u.id = a.user_id
	WHERE u.department IN %s
	GROUP BY u.%s`, groupByField, inClause, groupByField)

	var rows []DepartmentReportRow
	_, err := o.Raw(query, params...).QueryRows(&rows)
	if err != nil {
		return nil, err
	}

	// Convert to []map[string]interface{}
	var results []map[string]interface{}
	for _, row := range rows {
		results = append(results, map[string]interface{}{
			"group_value":         row.GroupValue,
			"user_count":          row.UserCount,
			"total_activities":    row.TotalActivities,
		})
	}

	return results, nil
}

