	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
		CreatedAt:   time.Now(),
	}

	_, err := o.Insert(user)
	if err != nil {
		return nil, err
	}

	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	var results []UserActivitySummary

	if len(usernames) == 0 {
		return results, nil
	}

	// Build placeholders for IN clause
	placeholders := ""
	for i, _ := range usernames {
		if i > 0 {
			placeholders += ","
		}
		placeholders += "?"
	}

	// Build base SQL query
	sql := `
        SELECT u.display_name, a.action_type, COUNT(*) as total, 
               SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
               AVG(a.duration_ms) as avg_duration
        FROM user_activity a 
        JOIN user_profile u ON a.user_id = u.id
        WHERE u.username IN (` + placeholders + `) AND a.created_at BETWEEN ? AND ?
    `

	// Build arguments
	args := make([]interface{}, 0, len(usernames)+2)
	for _, username := range usernames {
		args = append(args, username)
	}
	args = append(args, startDate, endDate)

	// Apply action type filter if specified
	if actionTypeFilter != "" {
		sql += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	sql += " GROUP BY u.display_name, a.action_type"

	// Execute query
	_, err := o.Raw(sql, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	var results []map[string]interface{}

	if len(departments) == 0 {
		return results, nil
	}

	// Validate groupByField is allowed
	switch groupByField {
	case "department", "role", "display_name":
		// Valid field
	default:
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build SQL query
	sql := `
        SELECT 
            u.` + groupByField + ` as group_value,
            COUNT(DISTINCT u.id) as user_count,
            COUNT(a.id) as total_activities
        FROM user_profile u
        LEFT JOIN user_activity a ON u.id = a.user_id
        WHERE u.department IN (?)
        GROUP BY u.` + groupByField + `
    `

	// Execute query and process results
	var rawResults []struct {
		GroupValue      string
		UserCount       int64
		TotalActivities int64
	}

	_, err := o.Raw(sql, departments).QueryRows(&rawResults)
	if err != nil {
		return nil, err
	}

	// Convert to required map format
	for _, r := range rawResults {
		results = append(results, map[string]interface{}{
			"group_value":       r.GroupValue,
			"user_count":        r.UserCount,
			"total_activities": r.TotalActivities,
		})
	}

	return results, nil
}

