	TotalActivities  int    `orm:"column(total_activities)"`
}

func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	_, err := o.Insert(user)
	if err != nil {
		return nil, err
	}

	return user, nil
}

func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build query with placeholders
	query := `
        SELECT u.display_name, a.action_type, COUNT(*) as total, 
               SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
               AVG(a.duration_ms) as avg_duration
        FROM user_activity a JOIN user_profile u ON a.user_id = u.id
        WHERE u.username IN (`
	for i := range usernames {
		if i > 0 {
			query += ", "
		}
		query += "?"
	}
	query += `) AND a.created_at BETWEEN ? AND ?`

	// Add action type filter if specified
	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
	}

	query += " GROUP BY u.display_name, a.action_type"

	// Prepare parameters
	params := make([]interface{}, 0, len(usernames)+2)
	for _, un := range usernames {
		params = append(params, un)
	}
	params = append(params, startDate, endDate)
	if actionTypeFilter != "" {
		params = append(params, actionTypeFilter)
	}

	// Execute query
	var results []UserActivitySummary
	_, err := o.Raw(query, params...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate groupByField
	validFields := map[string]bool{"department": true, "role": true, "display_name": true}
	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid group by field: %s, must be one of department, role, display_name", groupByField)
	}

	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Build query with placeholders
	query := fmt.Sprintf(`
        SELECT u.%s as group_value, 
               COUNT(DISTINCT u.id) as user_count, 
               COUNT(a.id) as total_activities
        FROM user_profile u 
        LEFT JOIN user_activity a ON u.id = a.user_id
        WHERE u.department IN (`, groupByField)
	for i := range departments {
		if i > 0 {
			query += ", "
		}
		query += "?"
	}
	query += `) GROUP BY u.` + groupByField

	// Prepare parameters
	params := make([]interface{}, 0, len(departments))
	for _, dept := range departments {
		params = append(params, dept)
	}

	// Execute query
	var rows []DepartmentReportRow
	_, err := o.Raw(query, params...).QueryRows(&rows)
	if err != nil {
		return nil, err
	}

	// Convert to []map[string]interface{}
	results := make([]map[string]interface{}, len(rows))
	for i, row := range rows {
		results[i] = map[string]interface{}{
			"group_value":        row.GroupValue,
			"user_count":         row.UserCount,
			"total_activities": row.TotalActivities,
		}
	}

	return results, nil
}

